t.script:
document.addEventListener('DOMContentLoaded', function() {
    // Password Toggle
    var toggleBtn = document.getElementById('togglePassword');
    var passwordInput = document.getElementById('password');

    if (toggleBtn && passwordInput) {
        toggleBtn.addEventListener('click', function() {
            var type = passwordInput.type === 'password' ? 'text' : 'password';
            passwordInput.type = type;
            this.querySelector('i').className = type === 'password' ? 'fas fa-eye-slash' : 'fas fa-eye';
        });
    }

    // Error Toast - Only show once per error
    var errorInput = document.getElementById('login-error');
    if (errorInput && errorInput.value) {
        var error = errorInput.value;
        var errorKey = 'login_error_shown_' + btoa(error);

        // Check if this error was already shown in this session
        if (!sessionStorage.getItem(errorKey)) {
            var message = 'Email hoặc mật khẩu không chính xác.';

            if (error === 'user_blocked') {
                message = 'Tài khoản của bạn đã bị vô hiệu hóa.';
            } else if (error !== 'access_denied' && error !== 'Wrong login/password') {
                message = error;
            }

            showToast(message, 'error');

            // Mark as shown
            sessionStorage.setItem(errorKey, 'true');

            // Clear after 10 seconds to allow showing again on new login attempt
            setTimeout(function() {
                sessionStorage.removeItem(errorKey);
            }, 10000);
        }

        // Clear the error input to prevent re-showing on page interaction
        errorInput.value = '';
    }

    // Check for password reset success message
    var urlParams = new URLSearchParams(window.location.search);
    if (urlParams.get('message') === 'password_reset_success') {
        showToast('Đổi mật khẩu thành công! Vui lòng đăng nhập với mật khẩu mới.', 'success');
        // Clean URL to prevent re-showing on refresh
        window.history.replaceState({}, document.title, window.location.pathname);
    }

    function showToast(message, type) {
        var container = document.getElementById('toastContainer');
        if (!container) return;

        // Clear existing toasts first
        container.innerHTML = '';

        var toast = document.createElement('div');
        toast.className = 'custom-toast ' + type;

        var iconClass = type === 'success' ? 'fa-check-circle' : 'fa-exclamation-circle';
        var iconColor = type === 'success' ? '#22c55e' : '#ef4444';

        toast.innerHTML = '<i class="fas ' + iconClass + ' toast-icon" style="color:' + iconColor + '"></i><span>' + message + '</span>';
        container.appendChild(toast);

        setTimeout(function() {
            toast.style.opacity = '0';
            toast.style.transform = 'translateX(100px)';
            setTimeout(function() { toast.remove(); }, 300);
        }, 5000);
    }
});
